const event = $input.first().json.events?.[0] || $input.first().json.body?.events?.[0];
const messageText = event?.message?.text || '';
const replyToken = event?.replyToken || '';
const userId = event?.source?.userId || '';

const urlMatch = messageText.match(/(https?:\/\/[^\s]+)/);
const targetUrl = urlMatch ? urlMatch[1] : '';

const ycMatch = targetUrl.match(/([A-Z]{2}\d{6,})/i) || targetUrl.match(/\/(\d+)(?:[\/?#]|$)/);
const caseId = ycMatch ? ycMatch[1].toUpperCase() : '';

if (!targetUrl) {
  throw new Error(`找不到網址。原始訊息：「${messageText}」長度=${messageText.length}`);
}

return [{ json: { targetUrl, caseId, replyToken, userId, rawMessage: messageText } }];

let html = $input.first().json.data || $input.first().json.body || '';
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
html = html.replace(/<!--[\s\S]*?-->/g, '');
html = html.replace(/<noscript[\s\S]*?<\/noscript>/gi, '');
const bodyMatch = html.match(/<body[\s\S]*?<\/body>/i);
let content = bodyMatch ? bodyMatch[0] : html;
content = content.replace(/\s+/g, ' ').trim();
if (content.length > 80000) content = content.substring(0, 80000);
return [{ json: { ...$('解析 LINE 指令').first().json, cleanedHtml: content, htmlLength: content.length } }];

